const transcript = 
$input.first().json.tracks[0].transcript
if (!Array.isArray(transcript) || transcript.length === 0) {
  return [{
    json: {
      chatInput: "Transcript not available or invalid video ID."
    }
  }];
}

// Join all transcript lines into a single string
const transcriptText = transcript.map(t => t.text).join(' ');

// Return as chatInput
return [{
  json: {
    chatInput: transcriptText
  }
}];

const inputText = $input.first().json.output;

function getFieldValue(text, field) {
  // Updated to stop at "---" or end of string, instead of a non-whitespace line
  const regex = new RegExp(`${field}:\\s*([\\s\\S]*?)(?=\\n---|$)`, 'i');
  const match = text.match(regex);
  return match ? match[1].trim() : '';
}

const summary = getFieldValue(inputText, '🎬 \\*\\*Summary\\*\\*');

return [{
  json: {
    summary
  }
}];
